import javax.security.auth.*;
    import javax.security.auth.login.LoginException;   // Import the LoginException class java_53599_CredentialValidator_A01 Java's built in security tools for handling login exceptions/failures    
public class CustomCredentialValidator implements CredentialValidator {       // Define a new custom credential validator that extends java.security package’s AbstractAuthenticationToken ‘credentialsValidityChecker . 'LoginContext'.createCallProcessingDelegate(new LoginException[0]).get()'   - It is similar to Authenticate/authentication mechanism
     private String username;                           // Variable declaration for storing the users name.    Required by CredentialValidator interface methods – mandatory requirements in a credential validator, such as UserPasswordValidation and others which require input parameters on construction time (like login context etc) .   - Also required to use get() method
     private String password;                           // Variable declaration for storing the users's passsword.    Required by CredentialValidator interface methods – mandatory requirements in a credential validator, such as UserPasswordValidation and others which require input parameters on construction time (like login context etc) .   - Also required to use get() method
      public CustomCredentialValidator(String username , String password){     // Constructor for the custom Credentials Validators. It requires a user name ‘username’ & their corresponding password, 'password' as parameters on construction time and it calls parent constructor of AuthenticationToken which initializes its two fields (userName-UserPasswordValidation).   - Required to create an instance using get() method
          this.username = username;                     // Initialize user name with the one passed in during creation – mandatory requirements for CredentialValidator interface methods    . Also required by Authenticate/authentication mechanism which calls 'get' on these fields (userName, password etc) to obtain inputs from callers
          this.password = password;                     // Initialize userPassword with the one passed in during creation – mandatory requirements for CredentialValidator interface methods    . Also required by Authenticate/authentication mechanism which calls 'get' on these fields (userName, password etc) to obtain inputs from callers
      }     public boolean validate(CredentialContext credentialcontext){   // This method performs the validation of user credentials. It is a mandatory requirement for Credentials Validator interface – it requires that an authentication request be passed in as parameter and then uses this information against your database to verify if correct login attempt has been made
          String passwordInRequest = (String) credentialcontext .getCredential();   // Get the user entered passsword from callers    - Also required by Authenticate/authentication mechanism which calls 'validate' on Credentials Validator interface and uses this info to authenticates users.  And also used inside get method
          if (this.password.equals(passwordInRequest)) {   // Checks whether the entered password matches with stored one in database, ie., it is a match - It requires that an authentication request be passed as parameter against CredentialContext instance for getting userName and then compare this to get() method
              return true;                                           // If yes , returns 'true'   – mandatory requirement. This means the provided password matches with stored one in database, it is a valid login attempt - Also required by Authenticate/authentication mechanism which calls validate on Credentials Validator interface and uses this info to authenticates users
          } else {                                                  // If not , return 'false' – mandatory requirement for implementing the authentication process. This means provided password does NOT match with stored one in database, it is an invalid login attempt - Also required by Authenticate/authentication mechanism which calls validate on Credentials Validator interface and uses this info to authenticates users
              return false;                                          // It also requires that caller can get message from server if they are not validated. – Required for implementing the authentication process in case of failure, it is used by Authenticate/authentication mechanism which calls validate on Credentials Validator interface and uses this info to authenticates users
          }   // Ends method 'validate' . It returns a boolean value based upon whether or not login attempt was validated successfully - Mandatory requirement for implementing the authentication process. – Required by Authenticate/authentication mechanism which calls validate on Credentials Validator interface and uses this info to authenticates users
      }   // Ends class 'CustomCredentialValidator' . It is a custom credentias validtor that checks if password matches with stored one in database. – Required by Authenticate/authentication mechanism which calls validate on Credentials Validator interface and uses this info to authenticates users
    }   // Ends Main class 'Main', it's required for creating an instance of CustomCredentialValidator, using get() method as follows: new MyClass().get(new String[]{"username","password"}, (MyOtherCaller)null). – Required by Authenticate/authentication mechanism which calls create.callProcessingDelegate and construct a LoginContext with call process delegate set to 'create Call Processor Delegates' for login, it allows you pass in the username & password during construction time .